package com.recettealarm.app;import android.app.*;import android.content.*;import android.os.*;import android.widget.*;
public class EditRecipeActivity extends Activity{DB db;EditText title,cat,serv,time,video,ing,qty,unit,step,min,note;long rid=0;public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);rid=getIntent().getLongExtra("id",0);LinearLayout r=UI.root(this);r.addView(UI.tv(this,"Nouvelle Recette",28,1));title=UI.input(this,"Nom recette");cat=UI.input(this,"Catégorie");serv=UI.input(this,"Nombre de personnes");time=UI.input(this,"Temps total minutes");video=UI.input(this,"Lien vidéo optionnel");r.addView(title);r.addView(cat);r.addView(serv);r.addView(time);r.addView(video);Button save=UI.btn(this,"Enregistrer la recette");r.addView(save);r.addView(UI.tv(this,"Ajouter ingrédient",22,1));ing=UI.input(this,"Nom ingrédient");qty=UI.input(this,"Quantité");unit=UI.input(this,"Unité: g, kg, ml, litre, verre...");r.addView(ing);r.addView(qty);r.addView(unit);Button ai=UI.btn(this,"Ajouter ingrédient");r.addView(ai);r.addView(UI.tv(this,"Ajouter étape anti-brûlure",22,1));step=UI.input(this,"Description étape");min=UI.input(this,"Durée minutes");note=UI.input(this,"Note sécurité: remuer, baisser le feu...");r.addView(step);r.addView(min);r.addView(note);Button ast=UI.btn(this,"Ajouter étape");r.addView(ast);save.setOnClickListener(v->{rid=db.saveRecipe(rid,val(title),val(cat),num(serv,4),num(time,30),val(video));UI.toast(this,"Recette enregistrée");});ai.setOnClickListener(v->{if(rid==0)save.performClick();db.addIng(rid,val(ing),val(qty),val(unit));UI.toast(this,"Ingrédient ajouté");});ast.setOnClickListener(v->{if(rid==0)save.performClick();db.addStep(rid,val(step),num(min,5),val(note));UI.toast(this,"Étape ajoutée");});}
 String val(EditText e){return e.getText().toString();}int num(EditText e,int d){try{return Integer.parseInt(val(e).trim());}catch(Exception x){return d;}}
}
